from vex import Guardrail, Verify

# Define brand voice guardrail
brand_guardrail = Guardrail("brand-consistency", {
    "brand_voice": {
        "tone": "professional-optimistic",
        "readability": ">70",
        "sentence_length": "15-25"
    }
})

# Wrapped agent execution
def safe_agent_run(agent, input):
    result = agent.run(input)
    verification = brand_guardrail.verify(result.final_output)
    if verification.passed:
        return result
    else:
        raise ValueError(f"Brand violation: {verification.failures}")

# Usage
content = safe_agent_run(writer, "Write about AI guardrails")
